import React from "react";
import styles from "./nav-button.module.css";

interface NavButtonProps {
  text: string;
  imgSrc?: string;
  isLink?: boolean;
  handleClick?: () => void; 
}

const NavButton: React.FC<NavButtonProps> = ({ text, imgSrc, isLink, handleClick }) => {
  return (
    <>
      {isLink ? (
        <a className={styles.nav__button} href="/contact">
          {text}
        </a>
      ) : (
        <button className={styles.nav__button} onClick={handleClick}>
          {text}
          <img src={imgSrc} alt="icon" width={10} height={10} />
        </button>
      )}
    </>
  );
};

export default NavButton;




